-- ── DATABASE SEED SCRIPT ───────────────────────────────────────────────────
-- This script contains a complete snapshot of the database.
-- It is organized into logical blocks to respect foreign key dependencies:
--
-- 1. General Setup   : Database settings and character encoding.
-- 2. Extensions      : Required Postgres extensions (uuid-ossp).
-- 3. Table Structures: CREATE TABLE statements (ordered by dependency).
-- 4. Data Inserts    : INSERT INTO statements (ordered by dependency).
-- 5. Indexes         : Primary and Secondary performance indexes.
-- 6. Constraints     : Foreign Key relationships (added last to ensure success).
--
-- ALL statements use IF NOT EXISTS or ON CONFLICT DO NOTHING for idempotency.
-- ─────────────────────────────────────────────────────────────────────────────

SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SELECT pg_catalog.set_config('search_path', '', false);
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;


SET default_tablespace = '';

SET default_table_access_method = heap;

-- Extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA public;

-- Table Structures (Ordered by dependency)
-- Table: companies
CREATE TABLE IF NOT EXISTS public.companies (
    company_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_name text NOT NULL,
    company_email text,
    industry text,
    subscription_plan text,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now(),
    is_active boolean DEFAULT true
);

-- Table: users
CREATE TABLE IF NOT EXISTS public.users (
    user_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_id uuid NOT NULL,
    full_name text,
    email text NOT NULL,
    password_hash text,
    role text,
    department text,
    designation text,
    is_active boolean DEFAULT true,
    last_login timestamp without time zone,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now(),
    lock_until timestamp without time zone,
    failed_attempts integer DEFAULT 0
);

-- Table: datasets
CREATE TABLE IF NOT EXISTS public.datasets (
    dataset_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_id uuid NOT NULL,
    uploaded_by uuid,
    dataset_name text NOT NULL,
    file_name text,
    file_size bigint,
    schema_json jsonb,
    upload_status text,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);

-- Table: permissions
CREATE TABLE IF NOT EXISTS public.permissions (
    company_id uuid NOT NULL,
    user_id uuid NOT NULL,
    dataset_id uuid NOT NULL,
    can_view boolean DEFAULT true,
    can_edit boolean DEFAULT false,
    can_delete boolean DEFAULT false,
    can_query boolean DEFAULT false,
    granted_by uuid,
    created_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);

-- Table: permission_requests
CREATE TABLE IF NOT EXISTS public.permission_requests (
    request_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_id uuid NOT NULL,
    user_id uuid NOT NULL,
    dataset_id uuid NOT NULL,
    permission_type text NOT NULL,
    status text DEFAULT 'pending'::text,
    requested_at timestamp without time zone DEFAULT now(),
    updated_at timestamp without time zone DEFAULT now()
);

-- Table: activity_logs
CREATE TABLE IF NOT EXISTS public.activity_logs (
    log_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_id uuid,
    user_id uuid,
    dataset_id uuid,
    activity_type text,
    activity_description text,
    module_name text,
    status text,
    ip_address inet,
    "timestamp" timestamp without time zone DEFAULT now()
);

-- Table: query_logs
CREATE TABLE IF NOT EXISTS public.query_logs (
    log_id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    company_id uuid,
    user_id uuid,
    dataset_id uuid,
    query_text text,
    query_type text,
    execution_time_ms integer,
    status text,
    rows_returned integer,
    "timestamp" timestamp without time zone DEFAULT now(),
    generated_code text,
    error_msg text
);

-- Table: password_reset_tokens
CREATE TABLE IF NOT EXISTS public.password_reset_tokens (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    user_id uuid NOT NULL,
    token text NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp without time zone DEFAULT now(),
    expires_at timestamp without time zone NOT NULL
);

