-- Indexes
CREATE INDEX idx_activity_logs_company_id ON public.activity_logs USING btree (company_id);

CREATE INDEX idx_activity_logs_dataset_id ON public.activity_logs USING btree (dataset_id);

CREATE INDEX idx_activity_logs_timestamp ON public.activity_logs USING btree ("timestamp");

CREATE INDEX idx_activity_logs_user_id ON public.activity_logs USING btree (user_id);

CREATE INDEX idx_companies_company_id ON public.companies USING btree (company_id);

CREATE INDEX idx_datasets_company_id ON public.datasets USING btree (company_id);

CREATE INDEX idx_datasets_dataset_id ON public.datasets USING btree (dataset_id);

CREATE INDEX idx_permissions_dataset_id ON public.permissions USING btree (dataset_id);

CREATE INDEX idx_permissions_user_id ON public.permissions USING btree (user_id);

CREATE INDEX idx_query_logs_company_id ON public.query_logs USING btree (company_id);

CREATE INDEX idx_query_logs_dataset_id ON public.query_logs USING btree (dataset_id);

CREATE INDEX idx_query_logs_timestamp ON public.query_logs USING btree ("timestamp");

CREATE INDEX idx_query_logs_user_id ON public.query_logs USING btree (user_id);

CREATE INDEX idx_users_company_id ON public.users USING btree (company_id);

CREATE INDEX idx_users_user_id ON public.users USING btree (user_id);

-- Constraints (FKs)
ALTER TABLE ONLY public.activity_logs
    ADD CONSTRAINT activity_logs_pkey PRIMARY KEY (log_id);

ALTER TABLE ONLY public.companies
    ADD CONSTRAINT companies_pkey PRIMARY KEY (company_id);

ALTER TABLE ONLY public.datasets
    ADD CONSTRAINT datasets_pkey PRIMARY KEY (dataset_id);

ALTER TABLE ONLY public.password_reset_tokens
    ADD CONSTRAINT password_reset_tokens_pkey PRIMARY KEY (id);

ALTER TABLE ONLY public.permission_requests
    ADD CONSTRAINT permission_requests_pkey PRIMARY KEY (request_id);

ALTER TABLE ONLY public.permissions
    ADD CONSTRAINT permissions_pkey PRIMARY KEY (user_id, dataset_id);

ALTER TABLE ONLY public.query_logs
    ADD CONSTRAINT query_logs_pkey PRIMARY KEY (log_id);

ALTER TABLE ONLY public.users
    ADD CONSTRAINT users_email_key UNIQUE (email);

ALTER TABLE ONLY public.users
    ADD CONSTRAINT users_pkey PRIMARY KEY (user_id);

ALTER TABLE ONLY public.activity_logs
    ADD CONSTRAINT activity_logs_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id);

ALTER TABLE ONLY public.activity_logs
    ADD CONSTRAINT activity_logs_dataset_id_fkey FOREIGN KEY (dataset_id) REFERENCES public.datasets(dataset_id);

ALTER TABLE ONLY public.activity_logs
    ADD CONSTRAINT activity_logs_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(user_id);

ALTER TABLE ONLY public.datasets
    ADD CONSTRAINT datasets_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.datasets
    ADD CONSTRAINT datasets_uploaded_by_fkey FOREIGN KEY (uploaded_by) REFERENCES public.users(user_id);

ALTER TABLE ONLY public.password_reset_tokens
    ADD CONSTRAINT password_reset_tokens_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(user_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permission_requests
    ADD CONSTRAINT permission_requests_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permission_requests
    ADD CONSTRAINT permission_requests_dataset_id_fkey FOREIGN KEY (dataset_id) REFERENCES public.datasets(dataset_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permission_requests
    ADD CONSTRAINT permission_requests_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(user_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permissions
    ADD CONSTRAINT permissions_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permissions
    ADD CONSTRAINT permissions_dataset_id_fkey FOREIGN KEY (dataset_id) REFERENCES public.datasets(dataset_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.permissions
    ADD CONSTRAINT permissions_granted_by_fkey FOREIGN KEY (granted_by) REFERENCES public.users(user_id);

ALTER TABLE ONLY public.permissions
    ADD CONSTRAINT permissions_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(user_id) ON DELETE CASCADE;

ALTER TABLE ONLY public.query_logs
    ADD CONSTRAINT query_logs_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id);

ALTER TABLE ONLY public.query_logs
    ADD CONSTRAINT query_logs_dataset_id_fkey FOREIGN KEY (dataset_id) REFERENCES public.datasets(dataset_id);

ALTER TABLE ONLY public.query_logs
    ADD CONSTRAINT query_logs_user_id_fkey FOREIGN KEY (user_id) REFERENCES public.users(user_id);

ALTER TABLE ONLY public.users
    ADD CONSTRAINT users_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(company_id) ON DELETE CASCADE;

